@Controller
class SamlController {
    private final SamlService samlService;

    public SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/")
    public void home(HttpServletResponse response) throws Exception {
        response.setContentType(MediaType.TEXT_HTML_VALUE);
        response.getWriter().write("<html><body><a href='/saml/login'>Login with SSO</a></body></html>");
    }

    @GetMapping("/saml/login")
    public void login(HttpServletResponse response) throws Exception {
        response.sendRedirect(samlService.buildAuthnRequestRedirectUrl());
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(HttpServletRequest request, HttpServletResponse response) throws Exception {
        String samlResponse = request.getParameter("SAMLResponse");
        String result = samlService.parseSamlResponse(samlResponse);
        response.setContentType(MediaType.TEXT_PLAIN_VALUE);
        response.getWriter().write(result);
    }
}